import{_ as e,o as r,c as a,a2 as d}from"./chunks/framework.c3r8iWL8.js";const m=JSON.parse('{"title":"Guide: Human-in-the-Loop & Governance","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/human-in-the-loop-governance.md","filePath":"guides/human-in-the-loop-governance.md","lastUpdated":1783100276000}'),o={name:"guides/human-in-the-loop-governance.md"};function i(n,t,s,l,h,c){return r(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="guide-human-in-the-loop-governance" tabindex="-1">Guide: Human-in-the-Loop &amp; Governance <a class="header-anchor" href="#guide-human-in-the-loop-governance" aria-label="Permalink to &quot;Guide: Human-in-the-Loop &amp; Governance&quot;">​</a></h1><p><strong>Decision:</strong> Where humans must decide, and how governance scales with AI velocity.</p><p>Related: <a href="./../GOVERNANCE.html">GOVERNANCE.md</a> · <a href="./../processes/overview.html">processes/overview.md</a></p><hr><h2 id="why-human-gates-still-matter-with-ai" tabindex="-1">Why human gates still matter with AI <a class="header-anchor" href="#why-human-gates-still-matter-with-ai" aria-label="Permalink to &quot;Why human gates still matter with AI&quot;">​</a></h2><p>AI increases <strong>drafting speed</strong> — not <strong>accountability</strong>. Irreversible or high-blast-radius decisions need a named human approver:</p><ul><li>Architecture commitments (ADRs)</li><li>External API contracts</li><li>Production promotion (especially T1)</li><li>Security and data policy</li><li>Incident command</li></ul><hr><h2 id="gate-models" tabindex="-1">Gate models <a class="header-anchor" href="#gate-models" aria-label="Permalink to &quot;Gate models&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Model</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Heavy gates (enterprise regulated)</strong></td><td>Audit trail; low drift</td><td>Slower; frustration if over-applied to T3</td></tr><tr><td><strong>Light gates (startup)</strong></td><td>Speed</td><td>Architecture and security debt</td></tr><tr><td><strong>Tier-based gates</strong></td><td>Risk-proportional</td><td>Requires honest tier classification</td></tr></tbody></table><p><strong>Recommended:</strong> Tier-based (<a href="./../GOVERNANCE.html">GOVERNANCE.md</a>) — T1 strict, T3 lighter.</p><hr><h2 id="raci-alternatives" tabindex="-1">RACI alternatives <a class="header-anchor" href="#raci-alternatives" aria-label="Permalink to &quot;RACI alternatives&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Full RACI per phase</strong></td><td>Clear</td><td>Documentation overhead</td></tr><tr><td><strong>DACI (Driver, Approver, Contributors, Informed)</strong></td><td>Simpler decisions</td><td>Less familiar</td></tr><tr><td><strong>Code owners only</strong></td><td>Git-native</td><td>Misses PO/SRE/accountability</td></tr></tbody></table><p>Use RACI or DACI in <strong>your</strong> handbook; this repo provides a reference RACI in GOVERNANCE.</p><hr><h2 id="human-vs-ai-by-activity" tabindex="-1">Human vs AI by activity <a class="header-anchor" href="#human-vs-ai-by-activity" aria-label="Permalink to &quot;Human vs AI by activity&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Activity</th><th>AI role</th><th>Human role</th></tr></thead><tbody><tr><td>Draft ADR</td><td>Full draft</td><td>Accept/reject/edit</td></tr><tr><td>Draft spec</td><td>OpenAPI skeleton</td><td>Approve contract</td></tr><tr><td>Write code</td><td>Generate + refactor</td><td>Steer; review PR</td></tr><tr><td>Write tests</td><td>Generate from spec</td><td>Review quality</td></tr><tr><td>PR review</td><td>First pass comments</td><td>Merge decision</td></tr><tr><td>Staging sign-off</td><td>Synthetics data</td><td>PO accepts behavior</td></tr><tr><td>Prod deploy T1</td><td>Metric analysis</td><td>SRE/ARCH approve</td></tr><tr><td>Incident RCA</td><td>Log summary draft</td><td>SRE validates</td></tr><tr><td>Policy exception</td><td>Risk summary</td><td>SEC/EM approve</td></tr></tbody></table><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>Rubber-stamping AI drafts</strong></td><td>Governance theater</td><td>Time-boxed review; ARB for cross-team</td></tr><tr><td><strong>Too many approvers</strong></td><td>Bottleneck defeats AI speed</td><td>Tier-based approvers</td></tr><tr><td><strong>Zero human review (&quot;AI said OK&quot;)</strong></td><td>Incidents</td><td>Merge requires human + CI</td></tr><tr><td><strong>Approvers not trained on AI limits</strong></td><td>False confidence</td><td>Onboarding module (SOP-011)</td></tr><tr><td><strong>No exception process</strong></td><td>Shadow IT bypass</td><td>SOP-012 with expiry</td></tr><tr><td><strong>PO skipped on staging</strong></td><td>Wrong product ships green</td><td>Explicit staging sign-off</td></tr><tr><td><strong>Architect unavailable</strong></td><td>De facto code-first</td><td>Delegate + ADR backlog SLA</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><p>Six phase gates (G0–G5) with tier-scoped approvers; document in team handbook; record <strong>your</strong> choices in <strong>your</strong> ADRs.</p><p>Reference procedures: <a href="./../sops/">SOP index</a>.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./ai-guardrails-security.html">AI guardrails</a> · <a href="./planning-adr-specs.html">Planning &amp; ADR</a></li></ul>',28)])])}const g=e(o,[["render",i]]);export{m as __pageData,g as default};
